```rust
// src/cli/status.rs
use clap::Args;
use hidapi::HidApi;
use serde::Serialize;
use colored::*;

const VENDOR_ID: u16 = 0x045E;
const PRODUCT_ID: u16 = 0x091B;

#[derive(Args)]
pub struct StatusArgs {
    #[arg(long)]
    pub json: bool,

    #[arg(long)]
    pub watch: bool,
}

#[derive(Serialize)]
pub struct Status {
    daemon: DaemonStatus,
    device: DeviceStatus,
    state: CurrentState,
    features: FeatureStatus,
    sensitivity: SensitivityStatus,
    audio_devices: AudioDevices,
}

#[derive(Serialize)]
pub struct DaemonStatus {
    running: bool,
    pid: Option<u32>,
    uptime_seconds: Option<u64>,
    log_level: String,
    events_processed: u64,
    start_time: Option<String>,
}

#[derive(Serialize)]
pub struct DeviceStatus {
    connected: bool,
    vendor_id: Option<String>,
    product_id: Option<String>,
    battery: Option<BatteryStatus>,
}

#[derive(Serialize)]
pub struct BatteryStatus {
    percent: u8,
    charging: bool,
}

#[derive(Serialize)]
pub struct CurrentState {
    mode: String,
    volume_percent: i32,
    mic_percent: i32,
    muted: bool,
    mic_muted: bool,
    mic_mode_remaining_seconds: Option<u32>,
    device_switching_active: bool,
    selected_output_device: Option<String>,
}

#[derive(Serialize)]
pub struct FeatureStatus {
    osd: OsdStatus,
    battery_monitor: BatteryMonitorStatus,
    system_tray: TrayStatus,
    media_control: MediaControlStatus,
    audio_feedback: AudioFeedbackStatus,
    event_hooks: EventHooksStatus,
    device_switching: DeviceSwitchingStatus,
}

pub fn run(args: StatusArgs) -> Result<(), Box<dyn std::error::Error>> {
    if args.watch {
        loop {
            let status = gather_status();
            print!("\x1B[2J\x1B[H"); // Clear screen
            if args.json {
                println!("{}", serde_json::to_string_pretty(&status)?);
            } else {
                print_status_formatted(&status);
            }
            std::thread::sleep(std::time::Duration::from_secs(1));
        }
    } else {
        let status = gather_status();
        if args.json {
            println!("{}", serde_json::to_string_pretty(&status)?);
        } else {
            print_status_formatted(&status);
        }

        // Exit code based on status
        if !status.daemon.running || !status.device.connected {
            std::process::exit(1);
        }
    }

    Ok(())
}

fn gather_status() -> Status {
    Status {
        daemon: check_daemon(),
        device: check_device(),
        state: get_current_state(),
        features: get_feature_status(),
        sensitivity: get_sensitivity_status(),
        audio_devices: list_audio_devices(),
    }
}

fn check_device() -> DeviceStatus {
    let api = HidApi::new().ok();

    if let Some(api) = api {
        if let Some(device_info) = api.device_list()
            .find(|d| d.vendor_id() == VENDOR_ID && d.product_id() == PRODUCT_ID) 
        {
            // Try to read battery level
            let battery = if let Ok(device) = api.open(VENDOR_ID, PRODUCT_ID) {
                crate::battery::BatteryStatus::read(&device)
                    .map(|b| BatteryStatus {
                        percent: b.percent.unwrap_or(0),
                        charging: b.charging,
                    })
            } else {
                None
            };

            return DeviceStatus {
                connected: true,
                vendor_id: Some(format!("{:04X}", VENDOR_ID)),
                product_id: Some(format!("{:04X}", PRODUCT_ID)),
                battery,
            };
        }
    }

    DeviceStatus {
        connected: false,
        vendor_id: None,
        product_id: None,
        battery: None,
    }
}

fn print_status_formatted(status: &Status) {
    println!("{}", "╭─ Surface Dial Status ────────────────────────────────────────╮".cyan());
    println!("{}", "│".cyan());

    // Daemon section
    println!("{}  {}", "│".cyan(), "Daemon".bold());
    if status.daemon.running {
        println!("{}    {} Running (PID {})", "│".cyan(), "✓".green(), 
            status.daemon.pid.unwrap_or(0));
        if let Some(uptime) = status.daemon.uptime_seconds {
            let hours = uptime / 3600;
            let mins = (uptime % 3600) / 60;
            println!("{}    • Uptime: {}h {}m", "│".cyan(), hours, mins);
        }
    } else {
        println!("{}    {} Not running", "│".cyan(), "✗".red());
    }
    println!("{}    • Log level: {}", "│".cyan(), status.daemon.log_level);
    println!("{}    • Events processed: {}", "│".cyan(), status.daemon.events_processed);
    println!("{}", "│".cyan());

    // Device section
    println!("{}  {}", "│".cyan(), "Device".bold());
    if status.device.connected {
        println!("{}    {} Surface Dial connected", "│".cyan(), "✓".green());
        println!("{}    • VID:PID {}:{}", "│".cyan(), 
            status.device.vendor_id.as_ref().unwrap(),
            status.device.product_id.as_ref().unwrap());
        if let Some(ref battery) = status.device.battery {
            let icon = if battery.charging { "🔌" } else { "🔋" };
            let color = if battery.percent > 50 { "green" } 
                       else if battery.percent > 20 { "yellow" } 
                       else { "red" };
            println!("{}    • {} Battery: {}%", "│".cyan(), icon, battery.percent);
        }
    } else {
        println!("{}    {} Not connected", "│".cyan(), "✗".red());
        println!("{}    • Wake the dial or check Bluetooth pairing", "│".cyan());
    }
    println!("{}", "│".cyan());

    // State section
    println!("{}  {}", "│".cyan(), "Current State".bold());
    println!("{}    • Mode: {}", "│".cyan(), status.state.mode);
    println!("{}    • Volume: {}%{}", "│".cyan(), status.state.volume_percent,
        if status.state.muted { " (muted)".red().to_string() } else { "".to_string() });
    println!("{}", "│".cyan());

    // Features section
    println!("{}  {}", "│".cyan(), "Features".bold());
    print_feature_line(&status.features.osd.enabled, "OSD", 
        &format!("{}, {}ms", status.features.osd.position, status.features.osd.timeout_ms));
    print_feature_line(&status.features.battery_monitor.enabled, "Battery Monitor",
        &format!("poll: {}s", status.features.battery_monitor.poll_interval_seconds));
    print_feature_line(&status.features.system_tray.enabled, "System Tray", "");
    print_feature_line(&status.features.media_control.enabled, "Media Control",
        &status.features.media_control.triple_click_action);
    print_feature_line(&status.features.audio_feedback.enabled, "Audio Feedback", "");
    print_feature_line(&status.features.event_hooks.enabled, "Event Hooks",
        &format!("{} scripts, {} webhooks", 
            status.features.event_hooks.scripts_count,
            status.features.event_hooks.webhooks_count));
    print_feature_line(&status.features.device_switching.enabled, "Device Switch",
        &status.features.device_switching.mode);
    println!("{}", "│".cyan());

    // Sensitivity section
    println!("{}  {}", "│".cyan(), "Sensitivity".bold());
    println!("{}    • Dead zone: {}", "│".cyan(), status.sensitivity.dead_zone);
    println!("{}    • Multiplier: {:.1}x", "│".cyan(), status.sensitivity.multiplier);
    println!("{}    • Invert: {}", "│".cyan(), if status.sensitivity.invert { "Yes" } else { "No" });
    println!("{}", "│".cyan());

    println!("{}", "╰──────────────────────────────────────────────────────────────╯".cyan());
}

fn print_feature_line(enabled: &bool, name: &str, detail: &str) {
    let icon = if *enabled { "✓".green() } else { "✗".red() };
    let status = if *enabled { "".to_string() } else { "(disabled)".dimmed().to_string() };
    let detail_str = if !detail.is_empty() && *enabled { 
        format!("({})", detail).dimmed().to_string() 
    } else { 
        "".to_string() 
    };
    println!("│    {} {:14} {} {}", icon, name, detail_str, status);
}
```

## Daemon Communication

Status command communicates with running daemon via:
1. **Unix socket** (macOS/Linux): `/tmp/surface-dial.sock`
2. **Named pipe** (Windows): `\\.\pipe\surface-dial`
3. **Fallback**: Read from daemon's state file if socket unavailable

```rust
fn get_current_state() -> CurrentState {
    // Try socket first
    if let Ok(state) = query_daemon_socket() {
        return state;
    }

    // Fallback to state file
    if let Ok(state) = read_state_file() {
        return state;
    }

    // Default if daemon not reachable
    CurrentState::default()
}
```

